import Colors from '@dynatrace/strato-design-tokens/colors';

import {
  apdexMap,
  type AutomaticColorPalette,
  type ColorPalette,
  type ColorPaletteDefinition,
  type DivergingColorPalette,
  logLevelMap,
  logLevelWithAlias,
  logStatusMap,
  logStatusWithAlias,
  securityRiskLevelMap,
  type SequentialColorPalette,
  statusMap,
  type ThemedColorPalette,
  thresholdMap,
  vulnerabilityStatusMap,
} from './color-palette.js';
import { prepareInvertedColorPalette } from '../utils/prepare-inverted-color-palette.js';

/**
 * @internal
 */
export const colorPalettesWithAlias = prepareInvertedColorPalette({
  'log-status': logStatusWithAlias,
  'log-level': logLevelWithAlias,
} as Record<string, ColorPaletteDefinition>);
/**
 * Map associating themed coloring options with their respective color palettes.
 * @internal
 */
const themedColoringMap: Record<ThemedColorPalette, ColorPaletteDefinition> =
  prepareInvertedColorPalette({
    categorical: Colors.Charts.Categorical,
    'purple-rain': Colors.Charts.CategoricalThemed.PurpleRain,
    swamps: Colors.Charts.CategoricalThemed.Swamps,
    fireplace: Colors.Charts.CategoricalThemed.Fireplace,
    'blue-steel': Colors.Charts.CategoricalThemed.BlueSteel,
    rainbow: Colors.Charts.Rainbow,
  } as Record<string, ColorPaletteDefinition>);
/**
 * Map associating automatic coloring options with their respective color palettes.
 * @internal
 */
const internalAutomaticColoringMap: Record<
  AutomaticColorPalette,
  ColorPaletteDefinition
> = prepareInvertedColorPalette({
  apdex: Colors.Charts.Apdex,
  'security-risk-level': Colors.Charts.SecurityRiskLevel,
  'vulnerability-status': Colors.Charts.VulnerabilityStatus,
  threshold: Colors.Charts.Threshold,
  status: Colors.Charts.Status,
} as Record<string, ColorPaletteDefinition>);
/**
 * Map associating automatic coloring options with their respective color palettes.
 * @internal
 */
export const automaticColoringMap: Record<
  AutomaticColorPalette,
  Record<string, string>
> = prepareInvertedColorPalette({
  'log-status': logStatusMap,
  'log-level': logLevelMap,
  apdex: apdexMap,
  'security-risk-level': securityRiskLevelMap,
  'vulnerability-status': vulnerabilityStatusMap,
  threshold: thresholdMap,
  status: statusMap,
} as Record<string, Record<string, string>>);
/**
 * Map associating sequential coloring options with their respective color palettes.
 * @internal
 */
export const sequentialColoringMap: Record<
  SequentialColorPalette,
  ColorPaletteDefinition
> = prepareInvertedColorPalette({
  'pink-purple': Colors.Charts.Sequential.PinkPurple,
  'blue-turquoise': Colors.Charts.Sequential.BlueTurquoise,
  blue: Colors.Charts.Sequential.Blue,
  grey: Colors.Charts.Sequential.Grey,
  moss: Colors.Charts.Sequential.Moss,
  turquoise: Colors.Charts.Sequential.Turquoise,
  pink: Colors.Charts.Sequential.Pink,
  yellow: Colors.Charts.Sequential.Yellow,
  petrol: Colors.Charts.Sequential.Petrol,
  purple: Colors.Charts.Sequential.Purple,
  pear: Colors.Charts.Sequential.Pear,
  brown: Colors.Charts.Sequential.Brown,
  red: Colors.Charts.Sequential.Red,
  magenta: Colors.Charts.Sequential.Magenta,
  orange: Colors.Charts.Sequential.Orange,
} as Record<string, ColorPaletteDefinition>);
/**
 * Map associating diverging coloring options with their respective color palettes.
 * @internal
 */
export const divergingColoringMap: Record<
  DivergingColorPalette,
  ColorPaletteDefinition
> = prepareInvertedColorPalette({
  'orange-blue': Colors.Charts.Diverging.OrangeBlue,
  'red-blue': Colors.Charts.Diverging.RedBlue,
  'red-purple': Colors.Charts.Diverging.RedPurple,
  'blue-moss': Colors.Charts.Diverging.BlueMoss,
  'purple-yellow': Colors.Charts.Diverging.PurpleYellow,
  'red-green': Colors.Charts.Diverging.RedGreen,
  'orange-petrol': Colors.Charts.Diverging.OrangePetrol,
  'pink-green': Colors.Charts.Diverging.PinkGreen,
} as Record<string, ColorPaletteDefinition>);
/**
 * Map associating all color palette options with their respective color palettes.
 * @internal
 */
export const colorPaletteMap: Record<ColorPalette, ColorPaletteDefinition> = {
  ...themedColoringMap,
  ...internalAutomaticColoringMap,
  ...colorPalettesWithAlias,
  ...sequentialColoringMap,
  ...divergingColoringMap,
};
